diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..2cf98f4804ba 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4808,6 +4808,94 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
   const CmpInst::Predicate Pred = I.getPredicate();
   Value *X;

+  // Fold: icmp pred (sdiv X, C), X where C > 1
+  // (X / C) < X  -->  X > 0  (when C > 1)
+  // (X / C) >= X -->  X <= 0 (when C > 1)
+  // (X / C) == X -->  X == 0 (when C > 1)
+  // (X / C) != X -->  X != 0 (when C > 1)
+  // This is because for C > 1:
+  //   - If X > 0: X / C < X (strictly less)
+  //   - If X <= 0: X / C >= X
+  //   - X / C == X only when X == 0
+  const APInt *DivC;
+  if (match(Op0, m_SDiv(m_Specific(Op1), m_APInt(DivC))) &&
+      DivC->isStrictlyPositive() && *DivC != 1) {
+    if (Pred == ICmpInst::ICMP_SLT)
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SGE)
+      return new ICmpInst(ICmpInst::ICMP_SLE, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_EQ)
+      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_NE)
+      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
+  }
+  // Same for unsigned division:
+  // (X / C) < X  -->  X != 0 (when C > 1)
+  // (X / C) >= X -->  X == 0 (when C > 1)
+  // (X / C) == X -->  X == 0 (when C > 1)
+  // (X / C) != X -->  X != 0 (when C > 1)
+  // Also handle signed predicates with unsigned division:
+  // (X / C) <s X  -->  X >s 0 (when C > 1)
+  // (X / C) >=s X -->  X <=s 0 (when C > 1)
+  if (match(Op0, m_UDiv(m_Specific(Op1), m_APInt(DivC))) &&
+      *DivC != 0 && *DivC != 1) {
+    if (Pred == ICmpInst::ICMP_ULT)
+      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_UGE)
+      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_EQ)
+      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_NE)
+      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SLT)
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SGE)
+      return new ICmpInst(ICmpInst::ICMP_SLE, Op1, Constant::getNullValue(Op1->getType()));
+  }
+
+  // Fold: icmp pred (lshr X, C), X where C > 0
+  // (X >> C) == X -->  X == 0 (when C > 0)
+  // (X >> C) != X -->  X != 0 (when C > 0)
+  // (X >> C) <=u X -->  true (when C > 0, X u>= 0 always true)
+  // (X >> C) >u X  -->  false (when C > 0)
+  // For signed predicates:
+  // (X >> C) sge X -->  X <=s 0 (i.e., X slt 1) (when C > 0)
+  // (X >> C) sgt X -->  X <s 0 (i.e., X slt 0) (when C > 0)
+  // (X >> C) sle X -->  X >=s 0 (i.e., X sgt -1) (when C > 0)
+  // (X >> C) slt X -->  X >s 0 (i.e., X sgt -1 is wrong, should be X >s 0) (when C > 0)
+  const APInt *ShrC;
+  if (match(Op0, m_LShr(m_Specific(Op1), m_APInt(ShrC))) &&
+      !ShrC->isZero()) {
+    if (Pred == ICmpInst::ICMP_EQ)
+      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_NE)
+      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_UGE)
+      return replaceInstUsesWith(I, Builder.getTrue());
+    if (Pred == ICmpInst::ICMP_ULT)
+      return replaceInstUsesWith(I, Builder.getFalse());
+    if (Pred == ICmpInst::ICMP_SGE)
+      return new ICmpInst(ICmpInst::ICMP_SLT, Op1, ConstantInt::get(Op1->getType(), 1));
+    if (Pred == ICmpInst::ICMP_SGT)
+      return new ICmpInst(ICmpInst::ICMP_SLT, Op1, Constant::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SLE)
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Constant::getAllOnesValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SLT)
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Constant::getNullValue(Op1->getType()));
+  }
+
+  // Fold: icmp pred (ashr X, C), X where C > 0
+  // (X ashr C) sge X -->  X <= 0 (i.e., X slt 1) (when C > 0)
+  // This is because ashr shifts in sign bits, making the result closer to 0 or more negative
+  const APInt *AShrC;
+  if (match(Op0, m_AShr(m_Specific(Op1), m_APInt(AShrC))) &&
+      !AShrC->isZero()) {
+    if (Pred == ICmpInst::ICMP_SGE)
+      return new ICmpInst(ICmpInst::ICMP_SLT, Op1, ConstantInt::get(Op1->getType(), 1));
+    if (Pred == ICmpInst::ICMP_SLT)
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, ConstantInt::get(Op1->getType(), -1));
+  }
+
   // Convert add-with-unsigned-overflow comparisons into a 'not' with compare.
   // (Op1 + X) u</u>= Op1 --> ~Op1 u</u>= X
   if (match(Op0, m_OneUse(m_c_Add(m_Specific(Op1), m_Value(X)))) &&

