  // Fold: icmp pred (sdiv X, C), X where C > 1
  // (X / C) < X  -->  X > 0  (when C > 1)
  // (X / C) >= X -->  X <= 0 (when C > 1)
  // (X / C) == X -->  X == 0 (when C > 1)
  // (X / C) != X -->  X != 0 (when C > 1)
  // This is because for C > 1:
  //   - If X > 0: X / C < X (strictly less)
  //   - If X <= 0: X / C >= X
  //   - X / C == X only when X == 0
  const APInt *DivC;
  if (match(Op0, m_SDiv(m_Specific(Op1), m_APInt(DivC))) &&
      DivC->isStrictlyPositive() && *DivC != 1) {
    if (Pred == ICmpInst::ICMP_SLT)
      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_SGE)
      return new ICmpInst(ICmpInst::ICMP_SLE, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_EQ)
      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_NE)
      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
  }
  // Same for unsigned division:
  // (X / C) < X  -->  X != 0 (when C > 1)
  // (X / C) >= X -->  X == 0 (when C > 1)
  // (X / C) == X -->  X == 0 (when C > 1)
  // (X / C) != X -->  X != 0 (when C > 1)
  if (match(Op0, m_UDiv(m_Specific(Op1), m_APInt(DivC))) &&
      *DivC != 0 && *DivC != 1) {
    if (Pred == ICmpInst::ICMP_ULT)
      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_UGE)
      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_EQ)
      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_NE)
      return new ICmpInst(ICmpInst::ICMP_NE, Op1, Constant::getNullValue(Op1->getType()));
  }

  // Fold: icmp pred (lshr X, C), X where C > 0
  // (X >> C) == X -->  X == 0 (when C > 0)
  // (X >> C) != X -->  X != 0 (when C > 0)
  // (X >> C) <= X -->  true (when C > 0, X u>= 0 always true)
  // (X >> C) > X  -->  false (when C > 0)
  // For signed predicates:
  // (X >> C) sge X -->  X <= 0 (i.e., X slt 1) (when C > 0)
  // (X >> C) slt X -->  X > 0 (i.e., X sgt -1) (when C > 0)
  const APInt *ShrC;
  if (match(Op0, m_LShr(m_Specific(Op1), m_APInt(ShrC))) &&
      !ShrC->isZero()) {
    if (Pred == ICmpInst::ICMP_EQ)
      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Constant::getNullValue(Op1->getType()));
    if (Pred == ICmpInst::ICMP_NE)
