  // (X ashr C) sge X -->  X <= 0 (i.e., X slt 1) (when C > 0)
  // This is because ashr shifts in sign bits, making the result closer to 0 or more negative
  const APInt *AShrC;
  if (match(Op0, m_AShr(m_Specific(Op1), m_APInt(AShrC))) &&
      !AShrC->isZero()) {
    if (Pred == ICmpInst::ICMP_SGE)
      return new ICmpInst(ICmpInst::ICMP_SLT, Op1, ConstantInt::get(Op1->getType(), 1));
    if (Pred == ICmpInst::ICMP_SLT)
      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, ConstantInt::get(Op1->getType(), -1));
  }
